import { useState, useEffect, useRef, useCallback } from "react";

// ─── STORAGE ──────────────────────────────────────────────────────────────────
// orders e admins: privados (por usuário/instância) — evita race conditions em storage compartilhado
// produtos e categorias: compartilhados entre todos os admins
const SK = {
  orders:     "wmakers_orders7",
  admins:     "wmakers_admins7",
  products:   "wmakers_products7",
  categories: "wmakers_categories7",
  chat:       "wmakers_chat7",
};
async function dbLoad(key, shared = false) {
  try { const r = await window.storage.get(key, shared); return r ? JSON.parse(r.value) : null; } catch { return null; }
}
async function dbSave(key, val, shared = false) {
  try { await window.storage.set(key, JSON.stringify(val), shared); } catch (e) { console.error("storage error", e); }
}

